-- Asignación técnicos a grupos
SELECT u.id, g.id, 0, 0, 0 FROM `glpi_users` u, `glpi_groups` g WHERE u.name='desarrollo1' AND g.name='DESARROLLO';
SELECT u.id, g.id, 0, 0, 0 FROM `glpi_users` u, `glpi_groups` g WHERE u.name='soporte1' AND g.name='SOPORTE AL USUARIO';
